"use client"

import { useState } from "react"
import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import * as z from "zod"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/Button"
import { Input } from "@/components/ui/Input"
import { useRouter } from "next/navigation"
import Link from "next/link"

const registerSchema = z.object({
  fullName: z.string().min(5, "Nombre completo requerido"),
  email: z.string().email("Correo electrónico inválido"),
  password: z.string().min(6, "Mínimo 6 caracteres"),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Las contraseñas no coinciden",
  path: ["confirmPassword"],
})

type RegisterForm = z.infer<typeof registerSchema>

export default function RegistroPage() {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [success, setSuccess] = useState(false)
  const router = useRouter()
  const supabase = createClient()

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterForm>({
    resolver: zodResolver(registerSchema),
  })

  const onSubmit = async (data: RegisterForm) => {
    setLoading(true)
    setError(null)

    try {
      // 1. Sign up user
      const { data: authData, error: signUpError } = await supabase.auth.signUp({
        email: data.email,
        password: data.password,
        options: {
          data: {
            full_name: data.fullName,
          }
        }
      })

      if (signUpError) throw signUpError

      if (authData.user) {
        // Note: In a production app with triggers, user_profiles is usually handled via DB trigger
        // but let's ensure it's created if not handled or for development speed
        const { error: profileError } = await supabase
          .from('user_profiles')
          .insert({
            id: authData.user.id,
            full_name: data.fullName,
            role_id: 2, // Default to Coordinador for this demo, or restricted in prod
          })

        if (profileError) console.error("Profile creation error:", profileError)
      }

      setSuccess(true)
    } catch (err: any) {
      setError(err.message || "Error al crear la cuenta.")
    } finally {
      setLoading(false)
    }
  }

  if (success) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center p-8 sm:p-20 text-center space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="w-24 h-24 bg-tertiary-fixed rounded-full flex items-center justify-center mx-auto">
          <span className="material-symbols-outlined text-tertiary text-5xl">mark_email_read</span>
        </div>
        <div className="space-y-2">
          <h2 className="text-4xl font-black font-headline text-on-surface tracking-tight">Verifique su correo</h2>
          <p className="text-on-surface-variant max-w-sm mx-auto">
            Hemos enviado un enlace de confirmación a su cuenta. Por favor verifíquela para activar su acceso.
          </p>
        </div>
        <Button onClick={() => router.push("/login")} variant="secondary" size="lg">
          VOLVER AL INICIO
        </Button>
      </div>
    )
  }

  return (
    <div className="flex-1 flex flex-col items-center justify-center p-8 sm:p-20">
      <div className="w-full max-w-md space-y-10">
        <div className="space-y-2">
          <h2 className="text-4xl font-black font-headline text-on-surface tracking-tight">
            Nueva Cuenta
          </h2>
          <p className="text-on-surface-variant">
            Cree su perfil de acceso operativo MasterIsimo.
          </p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          {error && (
            <div className="p-4 bg-error-container text-on-error-container rounded-xl flex items-center gap-3">
              <span className="material-symbols-outlined">error</span>
              <p className="text-sm font-medium">{error}</p>
            </div>
          )}

          <div className="space-y-5">
            <Input
              label="Nombre Completo"
              placeholder="Juan Pérez"
              icon="badge"
              error={errors.fullName?.message}
              {...register("fullName")}
            />
            <Input
              label="Correo Institucional"
              placeholder="jperez@isimo.com"
              icon="mail"
              error={errors.email?.message}
              {...register("email")}
            />
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <Input
                label="Contraseña"
                type="password"
                placeholder="••••••"
                icon="key"
                error={errors.password?.message}
                {...register("password")}
              />
              <Input
                label="Confirmar"
                type="password"
                placeholder="••••••"
                icon="lock_reset"
                error={errors.confirmPassword?.message}
                {...register("confirmPassword")}
              />
            </div>
          </div>

          <Button type="submit" variant="primary" size="lg" className="w-full" isLoading={loading}>
            SOLICITAR ACCESO
          </Button>
        </form>

        <p className="text-sm text-center text-on-surface-variant">
          ¿Ya tiene una cuenta?{" "}
          <Link 
            href="/login" 
            className="font-bold text-primary hover:text-primary-container transition-colors"
          >
            INICIAR SESIÓN
          </Link>
        </p>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { KanbanBoard } from "@/components/features/KanbanBoard"
import { Card } from "@/components/ui/Card"
import { createClient } from "@/lib/supabase/client"
import { Appointment, Dock, AppointmentStatus } from "@/types"

export default function KanbanPage() {
  const [appointments, setAppointments] = useState<Appointment[]>([])
  const [docks, setDocks] = useState<Dock[]>([])
  const supabase = createClient()

  // Centralized data fetching handling all uncompleted operations
  const fetchData = useCallback(async () => {
    // 1. Fetch appointments that are currently active (not finalized or cancelled)
    const { data: apptData, error: apptErr } = await supabase
      .from('appointments')
      .select('*, appointment_purchase_orders(*)')
      .in('status', ['PENDIENTE', 'EN_PORTERIA', 'EN_MUELLE', 'DESCARGANDO'])
      .order('created_at', { ascending: true })

    if (apptData) setAppointments(apptData as Appointment[])

    // 2. Fetch total active docks to calculate availability
    const { data: docksData } = await supabase
      .from('docks')
      .select('*')
      .eq('is_active', true)

    if (docksData) setDocks(docksData as Dock[])
  }, [supabase])

  // Subscriptions for real-time operation
  useEffect(() => {
    fetchData()

    const channelAppointments = supabase
      .channel('appointments-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, () => {
        fetchData()
      })
      .subscribe()

    const channelDocks = supabase
      .channel('docks-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'docks' }, () => {
        fetchData()
      })
      .subscribe()

    return () => { 
      supabase.removeChannel(channelAppointments)
      supabase.removeChannel(channelDocks)
    }
  }, [supabase, fetchData])

  // --- KPI COMPUTATIONS ---
  // 1. En Espera: Appointments that haven't reached the dock yet
  const enEspera = appointments.filter(a => ['PENDIENTE', 'EN_PORTERIA'].includes(a.status)).length

  // 2. Muelles Libres: Total active docks minus appointments currently occupying a dock
  const enMuelleOcupados = appointments.filter(a => ['EN_MUELLE', 'DESCARGANDO'].includes(a.status)).length
  const totalActivos = docks.length || 12 // fallback visually if no docks
  const muellesLibres = Math.max(0, totalActivos - enMuelleOcupados)

  // 3. Eficiencia: Percentage of appointments that are not late
  const totalEvaluados = appointments.filter(a => a.punctuality_status).length
  const aTiempo = appointments.filter(a => a.punctuality_status && a.punctuality_status !== 'TARDE').length
  const eficiencia = totalEvaluados > 0 
    ? Math.round((aTiempo / totalEvaluados) * 100) 
    : 100 // Default optimal base

  // Unified Status Updater for the Board
  const updateAppointmentStatus = async (id: string, newStatus: AppointmentStatus) => {
    // Optimistic Update
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status: newStatus } : a))

    // Server Update
    const { error } = await supabase
      .from('appointments')
      .update({ status: newStatus })
      .eq('id', id)

    if (error) fetchData() // Revert state from server if it failed
  }

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      {/* Dashboard Header & Stats */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-1">
          <p className="text-xs font-bold tracking-[0.3em] text-primary/60 uppercase">Vista Operativa</p>
          <h1 className="text-5xl font-black font-headline tracking-tighter text-on-surface">PANEL DE PATIO</h1>
        </div>

        {/* Real-time Bento Stats Row */}
        <div className="flex flex-wrap gap-4">
          <Card className="px-6 py-4 flex items-center gap-4 bg-white/50 border-none shadow-ambient">
            <div className="w-12 h-12 rounded-xl bg-primary-fixed flex items-center justify-center">
              <span className="material-symbols-outlined text-primary">local_shipping</span>
            </div>
            <div>
              <p className="text-[10px] font-bold text-on-surface-variant uppercase tracking-widest">En Espera</p>
              <p className="text-2xl font-black font-headline leading-none">{enEspera}</p>
            </div>
          </Card>
          <Card className="px-6 py-4 flex items-center gap-4 bg-white/50 border-none shadow-ambient">
            <div className="w-12 h-12 rounded-xl bg-tertiary-fixed flex items-center justify-center">
              <span className="material-symbols-outlined text-tertiary">stadium</span>
            </div>
            <div>
              <p className="text-[10px] font-bold text-on-surface-variant uppercase tracking-widest">Muelles Libres</p>
              <p className="text-2xl font-black font-headline leading-none">{muellesLibres}/{totalActivos}</p>
            </div>
          </Card>
          <Card className={`px-6 py-4 flex items-center gap-4 ${eficiencia < 80 ? 'bg-error-container text-on-error-container' : 'bg-primary-container text-white'} border-none shadow-elevated transition-colors`}>
            <div className={`w-12 h-12 rounded-xl ${eficiencia < 80 ? 'bg-error text-on-error' : 'bg-primary text-white'} flex items-center justify-center`}>
              <span className="material-symbols-outlined">{eficiencia < 80 ? 'warning' : 'speed'}</span>
            </div>
            <div className="flex flex-col">
              <p className="text-[10px] font-bold opacity-60 uppercase tracking-widest">Eficiencia</p>
              <p className="text-2xl font-black font-headline leading-none">{eficiencia}%</p>
            </div>
          </Card>
        </div>
      </div>

      {/* Kanban Board Area */}
      <KanbanBoard appointments={appointments} onStatusChange={updateAppointmentStatus} />
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createClient } from "@/lib/supabase/client"
import { Appointment, Dock, CediSettings } from "@/types"
import { Card } from "@/components/ui/Card"
import { Button } from "@/components/ui/Button"
import { Input } from "@/components/ui/Input"
import { DockTimeline } from "@/components/features/DockTimeline"
import { parseTime, formatTimeFromMinutes } from "@/lib/services/scheduling"

// ─── Confirmation Modal ─────────────────────────────────────
function ConfirmModal({ isOpen, onClose, onConfirm, title, message, loading }: {
  isOpen: boolean; onClose: () => void; onConfirm: () => void; title: string; message: string; loading: boolean
}) {
  if (!isOpen) return null
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-float w-full max-w-md mx-4 overflow-hidden animate-in zoom-in-95 duration-300" onClick={e => e.stopPropagation()}>
        <div className="p-8 space-y-4">
          <div className="w-14 h-14 bg-tertiary-fixed/30 rounded-2xl flex items-center justify-center mx-auto">
            <span className="material-symbols-outlined text-2xl text-tertiary">swap_horiz</span>
          </div>
          <h3 className="text-xl font-black font-headline text-center">{title}</h3>
          <p className="text-sm text-on-surface-variant text-center leading-relaxed">{message}</p>
          <div className="flex gap-3 pt-2">
            <Button variant="secondary" className="flex-1" onClick={onClose} disabled={loading}>Cancelar</Button>
            <Button className="flex-1" onClick={onConfirm} disabled={loading}>
              {loading ? 'Procesando...' : 'Confirmar Cambio'}
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── Edit Appointment Modal ─────────────────────────────────
function EditModal({ isOpen, onClose, appointment, docks, onSave, loading }: {
  isOpen: boolean; onClose: () => void; appointment: Appointment | null; docks: Dock[]; onSave: (id: string, dockId: number, time: string, endTime: string) => void; loading: boolean
}) {
  const [editDockId, setEditDockId] = useState('')
  const [editTime, setEditTime] = useState('')
  const [editEndTime, setEditEndTime] = useState('')

  useEffect(() => {
    if (appointment) {
      setEditDockId(appointment.dock_id?.toString() || '')
      setEditTime(appointment.scheduled_time?.substring(0, 5) || '')
      setEditEndTime(appointment.scheduled_end_time?.substring(0, 5) || '')
    }
  }, [appointment])

  if (!isOpen || !appointment) return null

  const totalBoxes = appointment.appointment_purchase_orders?.reduce((s, po) => s + (po.box_count || 0), 0) || appointment.box_count || 0

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-float w-full max-w-lg mx-4 overflow-hidden animate-in zoom-in-95 duration-300" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-8 py-6 border-b border-surface-container">
          <h3 className="text-xl font-black font-headline">Editar Cita</h3>
          <button onClick={onClose} className="p-1 rounded-lg hover:bg-surface-container transition-colors">
            <span className="material-symbols-outlined text-on-surface-variant">close</span>
          </button>
        </div>
        <div className="p-8 space-y-6">
          {/* Info header */}
          <div className="bg-surface-container-low p-4 rounded-xl flex items-center gap-4">
            <div className="bg-primary px-3 py-1.5 rounded-lg">
              <span className="text-white font-black text-sm tracking-tight">{appointment.license_plate}</span>
            </div>
            <div>
              <p className="font-bold text-sm">{appointment.company_name}</p>
              <p className="text-[10px] text-on-surface-variant/60">{totalBoxes} cajas · {appointment.estimated_duration_minutes} min estimados</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[10px] font-black tracking-widest uppercase text-primary/60 mb-2 block">Muelle Asignado</label>
              <select
                className="flex w-full rounded-xl border border-surface-container bg-surface-container-low/10 text-on-surface p-4 text-sm font-bold transition-all focus:outline-none focus:ring-2 focus:ring-primary/20 h-[56px] appearance-none"
                value={editDockId}
                onChange={e => setEditDockId(e.target.value)}
              >
                <option value="">-- Sin Asignar --</option>
                {docks.filter(d => d.is_active).map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-black tracking-widest uppercase text-primary/60 mb-2 block">Hora de Inicio</label>
              <Input type="time" value={editTime} onChange={e => setEditTime(e.target.value)} />
            </div>
          </div>

          <div>
            <label className="text-[10px] font-black tracking-widest uppercase text-primary/60 mb-2 block">Hora de Fin (Extendr si es necesario)</label>
            <Input type="time" value={editEndTime} onChange={e => setEditEndTime(e.target.value)} />
            <p className="text-[10px] text-on-surface-variant/50 mt-1">Modifica este campo si la descarga toma más del tiempo estimado.</p>
          </div>

          <Button className="w-full" onClick={() => onSave(appointment.id, parseInt(editDockId), editTime + ':00', editEndTime + ':00')} disabled={loading || !editDockId || !editTime}>
            {loading ? 'Guardando...' : 'Guardar Cambios'}
          </Button>
        </div>
      </div>
    </div>
  )
}

// ─── Main Page ──────────────────────────────────────────────
export default function MuellesPage() {
  const [date, setDate] = useState(() => new Date().toISOString().split('T')[0])
  const [appointments, setAppointments] = useState<Appointment[]>([])
  const [docks, setDocks] = useState<Dock[]>([])
  const [settings, setSettings] = useState<CediSettings | null>(null)
  const [loading, setLoading] = useState(true)
  const [actionLoading, setActionLoading] = useState(false)

  // Modal state
  const [confirmModal, setConfirmModal] = useState<{ appointmentId: string; newDockId: number; newTime: string } | null>(null)
  const [editModal, setEditModal] = useState<Appointment | null>(null)
  const [extendModal, setExtendModal] = useState<string | null>(null)

  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null)

  const supabase = createClient()

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ message, type })
    setTimeout(() => setToast(null), 3500)
  }

  const fetchData = useCallback(async () => {
    const [sRes, dRes, aRes] = await Promise.all([
      supabase.from('cedi_settings').select('*').single(),
      supabase.from('docks').select('*').eq('is_active', true).order('priority').order('id'),
      supabase.from('appointments').select(`*, appointment_purchase_orders(*)`).eq('scheduled_date', date).neq('status', 'CANCELADO').order('scheduled_time')
    ])

    if (sRes.data) setSettings(sRes.data)
    if (dRes.data) setDocks(dRes.data)
    if (aRes.data) setAppointments(aRes.data)
    setLoading(false)
  }, [supabase, date])

  useEffect(() => { 
    setLoading(true)
    fetchData() 
  }, [fetchData])

  // Real-time subscription
  useEffect(() => {
    const channel = supabase
      .channel('muelles-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, () => fetchData())
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [supabase, fetchData])

  // ─── Handlers ─────────────────────────────────────────────
  const handleAppointmentMove = useCallback((appointmentId: string, newDockId: number, newTime: string) => {
    setConfirmModal({ appointmentId, newDockId, newTime })
  }, [])

  const handleConfirmMove = async () => {
    if (!confirmModal) return
    setActionLoading(true)

    // ─── VALIDACIÓN DE COLISIÓN (Mejorada para manejar NULLs y estados) ───
    const appt = appointments.find(a => a.id === confirmModal.appointmentId)
    const duration = appt?.estimated_duration_minutes || 60
    const proposedStartMin = parseTime(confirmModal.newTime)
    const proposedEndMin = proposedStartMin + duration

    const hasCollision = appointments.some(a => 
      a.id !== confirmModal.appointmentId && 
      a.dock_id === confirmModal.newDockId &&
      a.status !== 'CANCELADO' &&
      // Choca si la cita existente termina después de que la nuestra empiece Y empieza antes de que la nuestra termine
      parseTime(a.scheduled_time) < proposedEndMin &&
      (parseTime(a.scheduled_end_time || '') || parseTime(a.scheduled_time) + (a.estimated_duration_minutes || 60)) > proposedStartMin
    )

    if (hasCollision) {
      showToast('Conflicto: El espacio en el muelle no está disponible.', 'error')
      setActionLoading(false)
      setConfirmModal(null)
      return
    }

    const newEndTime = formatTimeFromMinutes(proposedEndMin)

    const { error } = await supabase
      .from('appointments')
      .update({ 
        dock_id: confirmModal.newDockId, 
        scheduled_time: confirmModal.newTime,
        scheduled_end_time: newEndTime + ':00'
      })
      .eq('id', confirmModal.appointmentId)

    setActionLoading(false)
    setConfirmModal(null)

    if (error) {
      showToast('Error al reubicar la cita.', 'error')
    } else {
      showToast('Cita reubicada exitosamente.', 'success')
      fetchData()
    }
  }

  const handleAppointmentEdit = useCallback((appointment: Appointment) => {
    setEditModal(appointment)
  }, [])

  const handleSaveEdit = async (id: string, dockId: number, time: string, endTime: string) => {
    setActionLoading(true)

    const newStartMin = parseTime(time)
    const newEndMin = parseTime(endTime)
    const newDuration = newEndMin - newStartMin

    // ─── VALIDACIÓN DE COLISIÓN ───
    const hasCollision = appointments.some(a => 
      a.id !== id &&
      a.dock_id === dockId &&
      a.status !== 'CANCELADO' && a.status !== 'FINALIZADO' &&
      parseTime(a.scheduled_time) < newEndMin &&
      (a.scheduled_end_time ? parseTime(a.scheduled_end_time) : parseTime(a.scheduled_time) + (a.estimated_duration_minutes || 60)) > newStartMin
    )

    if (hasCollision) {
      showToast('Conflicto: El cambio choca con otra cita programada en este muelle.', 'error')
      setActionLoading(false)
      return
    }

    const { error } = await supabase
      .from('appointments')
      .update({ 
        dock_id: dockId, 
        scheduled_time: time, 
        scheduled_end_time: endTime,
        estimated_duration_minutes: newDuration > 0 ? newDuration : undefined
      })
      .eq('id', id)

    setActionLoading(false)
    setEditModal(null)

    if (error) {
      showToast('Error al actualizar la cita.', 'error')
    } else {
      showToast('Cita actualizada.', 'success')
      fetchData()
    }
  }

  const handleAppointmentExtend = useCallback((appointmentId: string, newEndTime?: string) => {
    if (newEndTime) {
      // Direct update via cascading shift
      handleConfirmExtendAction(appointmentId, newEndTime)
    } else {
      setExtendModal(appointmentId)
    }
  }, [appointments])

  const handleConfirmExtendAction = async (id: string, endTime: string) => {
    setActionLoading(true)

    const { data, error } = await supabase.rpc('shift_appointments_on_resize', {
      p_appointment_id: id,
      p_new_end_time: endTime
    })

    setActionLoading(false)
    setExtendModal(null)

    if (error) {
      showToast('Error al procesar el desplazamiento: ' + error.message, 'error')
    } else {
      const { shifted_count } = data[0] || { shifted_count: 0 }
      if (shifted_count > 0) {
        showToast(`Cita extendida. Se desplazaron ${shifted_count} vehículos para evitar choques.`, 'success')
      } else {
        showToast('Cita extendida exitosamente.', 'success')
      }
      fetchData()
    }
  }

  const handleConfirmExtend = async () => {
    if (!extendModal) return
    const appt = appointments.find(a => a.id === extendModal)
    if (!appt) return

    // Default +30 min extend from button
    const currentEndMin = parseTime(appt.scheduled_end_time || '') || (parseTime(appt.scheduled_time) + (appt.estimated_duration_minutes || 60))
    const newEndMin = currentEndMin + 30
    const h = Math.floor(newEndMin / 60)
    const m = newEndMin % 60
    const newEndTimeStr = `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:00`

    handleConfirmExtendAction(extendModal, newEndTimeStr)
  }

  // Stats
  const activeDocks = docks.length
  const occupiedDocks = new Set(appointments.filter(a => ['EN_MUELLE', 'DESCARGANDO'].includes(a.status)).map(a => a.dock_id)).size
  const totalAppointments = appointments.length

  // Find the dock for the confirm modal
  const confirmDock = confirmModal ? docks.find(d => d.id === confirmModal.newDockId) : null
  const confirmAppt = confirmModal ? appointments.find(a => a.id === confirmModal.appointmentId) : null

  return (
    <div className="space-y-8">
      {/* Toast */}
      {toast && (
        <div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-xl shadow-float font-bold text-sm flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${toast.type === 'success' ? 'bg-tertiary-fixed text-on-tertiary-fixed-variant' : 'bg-error-container text-on-error-container'}`}>
          <span className="material-symbols-outlined text-lg">{toast.type === 'success' ? 'check_circle' : 'error'}</span>
          {toast.message}
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-1">
          <p className="text-xs font-bold tracking-[0.3em] text-primary/60 uppercase">Visualización de Recursos</p>
          <h1 className="text-5xl font-black font-headline tracking-tighter text-on-surface">MUELLES</h1>
        </div>

        <div className="flex items-center gap-4">
          {/* Stats */}
          <div className="flex gap-3">
            <Card className="px-4 py-2.5 flex items-center gap-3 bg-white/50 border-none shadow-ambient">
              <div className="w-8 h-8 rounded-lg bg-tertiary-fixed flex items-center justify-center">
                <span className="material-symbols-outlined text-sm text-tertiary">warehouse</span>
              </div>
              <div>
                <p className="text-[9px] font-bold text-on-surface-variant uppercase tracking-widest">Muelles</p>
                <p className="text-lg font-black font-headline leading-none">{occupiedDocks}/{activeDocks}</p>
              </div>
            </Card>
            <Card className="px-4 py-2.5 flex items-center gap-3 bg-white/50 border-none shadow-ambient">
              <div className="w-8 h-8 rounded-lg bg-primary-fixed flex items-center justify-center">
                <span className="material-symbols-outlined text-sm text-primary">local_shipping</span>
              </div>
              <div>
                <p className="text-[9px] font-bold text-on-surface-variant uppercase tracking-widest">Citas</p>
                <p className="text-lg font-black font-headline leading-none">{totalAppointments}</p>
              </div>
            </Card>
          </div>

          {/* Date Picker */}
          <div className="flex items-center gap-2">
            <button 
              onClick={() => { const d = new Date(date); d.setDate(d.getDate() - 1); setDate(d.toISOString().split('T')[0]) }}
              className="p-2 rounded-xl bg-surface-container hover:bg-surface-container-high transition-colors"
            >
              <span className="material-symbols-outlined text-sm">chevron_left</span>
            </button>
            <Input 
              type="date" 
              value={date} 
              onChange={e => setDate(e.target.value)} 
              className="w-[180px] text-center font-bold"
            />
            <button 
              onClick={() => { const d = new Date(date); d.setDate(d.getDate() + 1); setDate(d.toISOString().split('T')[0]) }}
              className="p-2 rounded-xl bg-surface-container hover:bg-surface-container-high transition-colors"
            >
              <span className="material-symbols-outlined text-sm">chevron_right</span>
            </button>
          </div>
        </div>
      </div>

      {/* Timeline */}
      {loading || !settings ? (
        <div className="h-[400px] animate-pulse bg-surface-container rounded-2xl flex items-center justify-center">
          <p className="text-sm font-bold text-on-surface-variant/40">Cargando línea de tiempo...</p>
        </div>
      ) : docks.length === 0 ? (
        <Card variant="elevated" className="p-12 text-center">
          <span className="material-symbols-outlined text-[48px] text-primary/20 mb-4">warehouse</span>
          <h3 className="text-xl font-black font-headline text-on-surface/60">Sin Muelles Configurados</h3>
          <p className="text-sm text-on-surface-variant/50 mt-2 max-w-sm mx-auto">Dirígete a Configuración CEDI para crear muelles antes de visualizar la línea de tiempo.</p>
        </Card>
      ) : (
        <DockTimeline
          date={date}
          appointments={appointments}
          docks={docks}
          settings={settings}
          onAppointmentMove={handleAppointmentMove}
          onAppointmentExtend={handleAppointmentExtend}
          onAppointmentEdit={handleAppointmentEdit}
        />
      )}

      {/* Legend */}
      <div className="flex flex-wrap gap-3 justify-center">
        {[
          { label: 'Pendiente', cls: 'bg-surface-container-highest' },
          { label: 'En Patio', cls: 'bg-secondary-fixed' },
          { label: 'En Muelle', cls: 'bg-tertiary-fixed/60' },
          { label: 'Descargando', cls: 'bg-tertiary-fixed' },
          { label: 'Finalizado', cls: 'bg-primary-fixed' },
        ].map(s => (
          <div key={s.label} className="flex items-center gap-1.5">
            <div className={`w-3 h-3 rounded ${s.cls}`} />
            <span className="text-[10px] font-bold text-on-surface-variant/60 uppercase tracking-wider">{s.label}</span>
          </div>
        ))}
      </div>

      {/* Tip */}
      <p className="text-center text-[10px] text-on-surface-variant/30 font-bold uppercase tracking-widest">
        Arrastra para reubicar · Doble clic para editar · Hover en el botón de reloj para extender tiempo
      </p>

      {/* ═══ Confirm Move Modal ═══ */}
      <ConfirmModal
        isOpen={!!confirmModal}
        onClose={() => setConfirmModal(null)}
        onConfirm={handleConfirmMove}
        loading={actionLoading}
        title="Confirmar Reubicación"
        message={`¿Deseas mover la cita de ${confirmAppt?.license_plate || ''} (${confirmAppt?.company_name || ''}) al ${confirmDock?.name || 'muelle seleccionado'} a las ${confirmModal?.newTime?.substring(0, 5) || ''}?`}
      />

      {/* ═══ Edit Modal ═══ */}
      <EditModal
        isOpen={!!editModal}
        onClose={() => setEditModal(null)}
        appointment={editModal}
        docks={docks}
        onSave={handleSaveEdit}
        loading={actionLoading}
      />

      {/* ═══ Extend Time Modal ═══ */}
      <ConfirmModal
        isOpen={!!extendModal}
        onClose={() => setExtendModal(null)}
        onConfirm={handleConfirmExtend}
        loading={actionLoading}
        title="Extender Tiempo de Descarga"
        message={`¿Deseas extender 30 minutos adicionales al tiempo de descarga de ${appointments.find(a => a.id === extendModal)?.license_plate || 'esta cita'}? Esto actualizará la hora de fin en la línea de tiempo.`}
      />
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createClient } from "@/lib/supabase/client"
import { Card } from "@/components/ui/Card"
import { Input } from "@/components/ui/Input"
import { Environment } from "@/types"

interface CapacitySummary {
  environment: Environment
  normalLimit: number
  extendedLimit: number
  currentBoxes: number
  appointmentCount: number
  extendedStartTime?: string
  extendedEndTime?: string
}

export default function ResumenDiarioPage() {
  const [date, setDate] = useState(() => new Date().toISOString().split('T')[0])
  const [summaries, setSummaries] = useState<CapacitySummary[]>([])
  const [loading, setLoading] = useState(true)
  const [totalBoxes, setTotalBoxes] = useState(0)
  const [totalAppointments, setTotalAppointments] = useState(0)

  const supabase = createClient()

  const fetchData = useCallback(async () => {
    setLoading(true)

    // Fetch environments, capacity limits, and appointments in parallel
    const [envRes, capRes, apptRes] = await Promise.all([
      supabase.from('environments').select('*').eq('is_active', true).order('id'),
      supabase.from('daily_capacity_limits').select('*').eq('is_active', true),
      supabase.from('appointments').select('id, box_count, environment_id, status, requires_extended_hours, is_forced_assignment, appointment_purchase_orders(box_count)')
        .eq('scheduled_date', date)
        .neq('status', 'CANCELADO'),
    ])

    const environments = envRes.data || []
    const capacityLimits = capRes.data || []
    const appointments = apptRes.data || []

    let grandTotalBoxes = 0
    let grandTotalAppts = 0

    const results: CapacitySummary[] = environments.map((env) => {
      const limit = capacityLimits.find(c => c.environment_id === env.id)
      const envAppts = appointments.filter(a => a.environment_id === env.id)

      const envBoxes = envAppts.reduce((total, appt) => {
        const poBoxes = appt.appointment_purchase_orders?.reduce(
          (s: number, po: { box_count: number }) => s + (po.box_count || 0), 0
        ) || 0
        return total + (poBoxes || appt.box_count || 0)
      }, 0)

      grandTotalBoxes += envBoxes
      grandTotalAppts += envAppts.length

      return {
        environment: env,
        normalLimit: limit?.normal_box_limit || 0,
        extendedLimit: limit?.extended_box_limit || 0,
        currentBoxes: envBoxes,
        appointmentCount: envAppts.length,
        extendedStartTime: limit?.extended_start_time,
        extendedEndTime: limit?.extended_end_time,
      }
    })

    // Include unassigned appointments (no environment_id)
    const unassignedAppts = appointments.filter(a => !a.environment_id)
    const unassignedBoxes = unassignedAppts.reduce((total, appt) => {
      const poBoxes = appt.appointment_purchase_orders?.reduce(
        (s: number, po: { box_count: number }) => s + (po.box_count || 0), 0
      ) || 0
      return total + (poBoxes || appt.box_count || 0)
    }, 0)
    grandTotalBoxes += unassignedBoxes
    grandTotalAppts += unassignedAppts.length

    setTotalBoxes(grandTotalBoxes)
    setTotalAppointments(grandTotalAppts)
    setSummaries(results)
    setLoading(false)
  }, [supabase, date])

  useEffect(() => { fetchData() }, [fetchData])

  // Real-time subscription
  useEffect(() => {
    const channel = supabase
      .channel('resumen-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, () => fetchData())
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [supabase, fetchData])

  const getPercentage = (current: number, limit: number) => limit > 0 ? Math.round((current / limit) * 100) : 0

  const getBarColor = (current: number, normalLimit: number, extendedLimit: number) => {
    if (normalLimit === 0) return 'bg-surface-container'
    if (current > extendedLimit) return 'bg-error' // Over extended = critical
    if (current > normalLimit) return 'bg-amber-500' // Over normal = warning
    if (current > normalLimit * 0.8) return 'bg-yellow-400' // 80%+ = caution
    return 'bg-tertiary' // Healthy
  }

  const getStatusLabel = (current: number, normalLimit: number, extendedLimit: number) => {
    if (normalLimit === 0) return { text: 'Sin Configurar', color: 'text-on-surface-variant/40' }
    if (current > extendedLimit) return { text: '🔴 SOBRECUPO CRÍTICO', color: 'text-error font-black' }
    if (current > normalLimit) return { text: '🟡 HORARIO EXTENDIDO', color: 'text-amber-600 font-bold' }
    if (current > normalLimit * 0.8) return { text: '🟠 ACERCÁNDOSE AL LÍMITE', color: 'text-yellow-600 font-bold' }
    return { text: '🟢 DENTRO DE CAPACIDAD', color: 'text-tertiary font-bold' }
  }

  const dateLabel = new Date(date + 'T12:00:00').toLocaleDateString('es-CO', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })

  return (
    <div className="space-y-10">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-1">
          <p className="text-xs font-bold tracking-[0.3em] text-primary/60 uppercase">Control de Capacidad</p>
          <h1 className="text-5xl font-black font-headline tracking-tighter text-on-surface">RESUMEN DIARIO</h1>
          <p className="text-sm text-on-surface-variant/60 font-medium capitalize">{dateLabel}</p>
        </div>

        <div className="flex items-center gap-4">
          {/* Stats */}
          <Card className="px-5 py-3 flex items-center gap-4 bg-white/50 border-none shadow-ambient">
            <div className="w-10 h-10 rounded-xl bg-primary-fixed flex items-center justify-center">
              <span className="material-symbols-outlined text-primary">inventory_2</span>
            </div>
            <div>
              <p className="text-[9px] font-bold text-on-surface-variant uppercase tracking-widest">Total Cajas</p>
              <p className="text-xl font-black font-headline leading-none">{totalBoxes.toLocaleString()}</p>
            </div>
          </Card>
          <Card className="px-5 py-3 flex items-center gap-4 bg-white/50 border-none shadow-ambient">
            <div className="w-10 h-10 rounded-xl bg-tertiary-fixed flex items-center justify-center">
              <span className="material-symbols-outlined text-tertiary">local_shipping</span>
            </div>
            <div>
              <p className="text-[9px] font-bold text-on-surface-variant uppercase tracking-widest">Citas</p>
              <p className="text-xl font-black font-headline leading-none">{totalAppointments}</p>
            </div>
          </Card>

          {/* Date Picker */}
          <div className="flex items-center gap-2">
            <button 
              onClick={() => { const d = new Date(date); d.setDate(d.getDate() - 1); setDate(d.toISOString().split('T')[0]) }}
              className="p-2 rounded-xl bg-surface-container hover:bg-surface-container-high transition-colors"
            >
              <span className="material-symbols-outlined text-sm">chevron_left</span>
            </button>
            <Input 
              type="date" 
              value={date} 
              onChange={e => setDate(e.target.value)}
              className="w-[180px] text-center font-bold"
            />
            <button 
              onClick={() => { const d = new Date(date); d.setDate(d.getDate() + 1); setDate(d.toISOString().split('T')[0]) }}
              className="p-2 rounded-xl bg-surface-container hover:bg-surface-container-high transition-colors"
            >
              <span className="material-symbols-outlined text-sm">chevron_right</span>
            </button>
          </div>
        </div>
      </div>

      {/* Capacity Bars */}
      {loading ? (
        <div className="space-y-6">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="h-36 animate-pulse bg-surface-container rounded-2xl" />
          ))}
        </div>
      ) : summaries.length === 0 ? (
        <Card variant="elevated" className="p-12 text-center">
          <span className="material-symbols-outlined text-[48px] text-primary/20 mb-4">monitoring</span>
          <h3 className="text-xl font-black font-headline text-on-surface/60">Sin Ambientes Configurados</h3>
          <p className="text-sm text-on-surface-variant/50 mt-2 max-w-sm mx-auto">Configura ambientes y límites de capacidad en Configuración CEDI para ver el resumen.</p>
        </Card>
      ) : (
        <div className="space-y-6">
          {summaries.map((s) => {
            const normalPct = getPercentage(s.currentBoxes, s.normalLimit)
            const extendedPct = getPercentage(s.currentBoxes, s.extendedLimit)
            const barColor = getBarColor(s.currentBoxes, s.normalLimit, s.extendedLimit)
            const status = getStatusLabel(s.currentBoxes, s.normalLimit, s.extendedLimit)
            const barWidth = s.extendedLimit > 0 ? Math.min((s.currentBoxes / s.extendedLimit) * 100, 100) : 0
            const normalMarker = s.extendedLimit > 0 ? (s.normalLimit / s.extendedLimit) * 100 : 50

            return (
              <Card key={s.environment.id} variant="elevated" className="p-6 space-y-4 overflow-hidden relative">
                {/* Over-capacity pulsing glow */}
                {s.currentBoxes > s.extendedLimit && (
                  <div className="absolute inset-0 bg-error/5 animate-pulse pointer-events-none" />
                )}

                {/* Header Row */}
                <div className="flex items-center justify-between relative z-10">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-xl flex items-center justify-center" style={{ backgroundColor: s.environment.color + '20' }}>
                      <span className="material-symbols-outlined text-xl" style={{ color: s.environment.color }}>{s.environment.icon}</span>
                    </div>
                    <div>
                      <h3 className="font-black font-headline text-lg text-on-surface">{s.environment.display_name}</h3>
                      <p className={`text-[10px] uppercase tracking-wider ${status.color}`}>{status.text}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-3xl font-black font-headline text-on-surface leading-none">{s.currentBoxes.toLocaleString()}</p>
                    <p className="text-[10px] text-on-surface-variant/50 font-bold mt-1">
                      de {s.normalLimit.toLocaleString()} normal / {s.extendedLimit.toLocaleString()} ext.
                    </p>
                  </div>
                </div>

                {/* Capacity Bar */}
                <div className="relative z-10">
                  <div className="h-4 bg-surface-container rounded-full relative overflow-hidden">
                    {/* Filled portion */}
                    <div 
                      className={`h-full rounded-full transition-all duration-700 ease-out ${barColor} ${s.currentBoxes > s.extendedLimit ? 'animate-pulse' : ''}`}
                      style={{ width: `${barWidth}%` }}
                    />
                    {/* Normal limit marker */}
                    {s.normalLimit > 0 && (
                      <div 
                        className="absolute top-0 h-full w-0.5 bg-on-surface/30"
                        style={{ left: `${normalMarker}%` }}
                      />
                    )}
                  </div>
                  {/* Labels under bar */}
                  <div className="flex justify-between mt-1.5">
                    <span className="text-[9px] font-bold text-on-surface-variant/40">0</span>
                    {s.normalLimit > 0 && (
                      <span className="text-[9px] font-bold text-on-surface-variant/60" style={{ marginLeft: `${normalMarker - 5}%` }}>
                        Normal: {s.normalLimit.toLocaleString()}
                      </span>
                    )}
                    <span className="text-[9px] font-bold text-on-surface-variant/40">
                      Ext: {s.extendedLimit.toLocaleString()}
                    </span>
                  </div>
                </div>

                {/* Stats Row */}
                <div className="flex gap-4 relative z-10">
                  <div className="flex items-center gap-2 bg-surface-container-low px-3 py-2 rounded-lg">
                    <span className="material-symbols-outlined text-sm text-on-surface-variant/40">local_shipping</span>
                    <span className="text-xs font-bold">{s.appointmentCount} citas</span>
                  </div>
                  <div className="flex items-center gap-2 bg-surface-container-low px-3 py-2 rounded-lg">
                    <span className="material-symbols-outlined text-sm text-on-surface-variant/40">percent</span>
                    <span className="text-xs font-bold">{normalPct}% del normal</span>
                  </div>
                  {s.extendedStartTime && (
                    <div className="flex items-center gap-2 bg-surface-container-low px-3 py-2 rounded-lg">
                      <span className="material-symbols-outlined text-sm text-on-surface-variant/40">schedule</span>
                      <span className="text-xs font-bold">Ext: {s.extendedStartTime?.substring(0,5)} – {s.extendedEndTime?.substring(0,5)}</span>
                    </div>
                  )}
                </div>
              </Card>
            )
          })}
        </div>
      )}

      {/* Footer Tip */}
      <p className="text-center text-[10px] text-on-surface-variant/30 font-bold uppercase tracking-widest">
        Datos en tiempo real · Selecciona una fecha para consultar cualquier día
      </p>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Appointment } from "@/types"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/Button"
import { cn, formatDate, formatTime } from "@/lib/utils"

interface AppointmentDetailsModalProps {
  isOpen: boolean
  onClose: () => void
  appointment: Appointment | null
  onSuccess?: () => void
}

export function AppointmentDetailsModal({ isOpen, onClose, appointment, onSuccess }: AppointmentDetailsModalProps) {
  const [newNote, setNewNote] = useState("")
  const [noteHistory, setNoteHistory] = useState("")
  const [isHistoryExpanded, setIsHistoryExpanded] = useState(true)
  const [isEditingHistory, setIsEditingHistory] = useState(false)
  const [editingContent, setEditingContent] = useState("")
  const [saving, setSaving] = useState(false)
  const supabase = createClient()

  useEffect(() => {
    if (appointment) {
      setNoteHistory(appointment.notes || appointment.comments || "")
      setNewNote("")
    }
  }, [appointment])

  if (!isOpen || !appointment) return null

  const handleSaveNotes = async () => {
    if (!newNote.trim()) return

    setSaving(true)
    try {
      const timestamp = new Date().toLocaleString('es-CO', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit' 
      })
      const noteEntry = `[${timestamp}] ${newNote.trim()}`
      const updatedNotes = noteHistory ? `${noteHistory}\n${noteEntry}` : noteEntry

      const { error } = await supabase
        .from('appointments')
        .update({ notes: updatedNotes } as any)
        .eq('id', appointment.id)

      if (error) throw error

      setNoteHistory(updatedNotes)
      setNewNote("") // Clears the textarea after appending
      onSuccess?.()
      // We explicitly don't close the modal so they can continue looking at the history.
    } catch (err: any) {
      if (err.message?.includes("column") || err.code === 'PGRST204') {
        alert("⚠️ Error: La base de datos requiere una actualización.\n\nPor favor ejecuta este comando en el Editor SQL de tu Supabase:\n\nALTER TABLE public.appointments ADD COLUMN IF NOT EXISTS notes text;")
      } else {
        alert("Error al guardar: " + err.message)
      }
    } finally {
      setSaving(false)
    }
  }

  const toggleEditHistory = () => {
    if (!isEditingHistory) {
      setEditingContent(noteHistory)
    }
    setIsEditingHistory(!isEditingHistory)
  }

  const handleSaveEditedHistory = async () => {
    setSaving(true)
    try {
      const { error } = await supabase
        .from('appointments')
        .update({ notes: editingContent } as any)
        .eq('id', appointment.id)

      if (error) throw error

      setNoteHistory(editingContent)
      setIsEditingHistory(false)
      onSuccess?.()
    } catch (err: any) {
      if (err.message?.includes("column") || err.code === 'PGRST204') {
        alert("⚠️ Error: La base de datos requiere una actualización.\n\nPor favor ejecuta este comando en el Editor SQL de tu Supabase:\n\nALTER TABLE public.appointments ADD COLUMN IF NOT EXISTS notes text;")
      } else {
        alert("Error al guardar: " + err.message)
      }
    } finally {
      setSaving(false)
    }
  }

  const getPunctualityStyle = (status?: string | null) => {
    if (!status || status === 'N/A (Sin Cita)') return "bg-surface-container-high text-on-surface-variant"
    if (status === 'TARDE') return "bg-red-100 text-red-700 border-red-200"
    if (status === 'A_TIEMPO') return "bg-green-100 text-green-700 border-green-200"
    return "bg-blue-100 text-blue-700 border-blue-200"
  }

  const waitTimeStr = appointment.arrival_time && appointment.start_unloading_time
    ? `${Math.round((new Date(appointment.start_unloading_time).getTime() - new Date(appointment.arrival_time).getTime()) / 60000)} min`
    : appointment.arrival_time
      ? `${Math.round((new Date().getTime() - new Date(appointment.arrival_time).getTime()) / 60000)} min (activo)`
      : '--'

  const unloadingTimeStr = appointment.start_unloading_time && appointment.end_unloading_time
    ? `${Math.round((new Date(appointment.end_unloading_time).getTime() - new Date(appointment.start_unloading_time).getTime()) / 60000)} min`
    : appointment.start_unloading_time
      ? `${Math.round((new Date().getTime() - new Date(appointment.start_unloading_time).getTime()) / 60000)} min (activo)`
      : '--'

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />
      <div className="relative w-full max-w-4xl bg-surface-container-lowest rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200">

        {/* Header - Ethereal Style */}
